const HTML_HEADERS = {
  'content-type': 'text/html; charset=utf-8',
  'cache-control': 'public, max-age=300, s-maxage=600',
  'x-content-type-options': 'nosniff',
  'referrer-policy': 'strict-origin-when-cross-origin',
};
const JSON_HEADERS = {
  'content-type': 'application/json; charset=utf-8',
  'cache-control': 'public, max-age=300, s-maxage=600',
  'access-control-allow-origin': '*',
};

function html(body){ return new Response(body, { headers: HTML_HEADERS }); }
function json_(obj){ return new Response(typeof obj === 'string' ? obj : JSON.stringify(obj), { headers: JSON_HEADERS }); }
function notFound(){ return new Response('Not found', { status: 404 }); }

const ROUTES = {
  '/': HOME,
  '/portal': HOME,
  '/demo-region': REGION,
  '/demo-division': DIVISION,
  '/demo-district': DISTRICT,
  '/demo-school': SCHOOL,
  '/williamstownprimary': WILLIAMSTOWN_PRIMARY,
  '/williamstowndistrict': WILLIAMSTOWN_DISTRICT,
  '/hobsonsbay': HOBSONSBAY_DIVISION,
};

export default {
  async fetch(request){
    const url = new URL(request.url);
    const p = url.pathname.replace(/\/$/,'') || '/';
    if (p === '/health'){
      return json_({ ok:true, worker:'schoolsportportal', version:'2026-04-29-redesign', ts: new Date().toISOString() });
    }
    if (p === '/api/data.json'){
      return json_(DATA_JSON);
    }
    if (p in ROUTES){
      return html(ROUTES[p]);
    }
    // Fallback to homepage for unknown paths (existing behaviour preserved)
    return html(HOME);
  }
};
